class Solution:
    def solve(self, root):
        self.ans = float('-inf')
        def max_gain(node):
            if node is None:
                return 0
            l_sum = max(max_gain(node.left), 0)
            r_sum = max(max_gain(node.right), 0)
            price_new = node.val + l_sum + r_sum
            self.ans = max(self.ans, price_new)
            return node.val + max(l_sum, r_sum)
        max_gain(root)
        return self.ans

