class Solution {
public:
    int solve(TreeNode *root) {
        this->ans = INT_MIN;
        int max_gain(TreeNode *node) {
            if (node == NULL) return 0;
            int l_sum = max(max_gain(node->left), 0);
            int r_sum = max(max_gain(node->right), 0);
            int price_new = node->val + l_sum + r_sum;
            this->ans = max(this->ans, price_new);
            return node->val + max(l_sum, r_sum);
        }
        max_gain(root);
        return this->ans;
    }
};
